    input wire init,
    input wire [7:0] data,
    input wire data_en,
    output reg [7:0] crcOut
);

always @(posedge clk) begin
    if (init)
        crcOut <= 8'b0;
    else if (data_en) begin
        crcOut[0] <= (crcOut[0] ^ crcOut[2] ^ crcOut[4] ^ crcOut[5] ^ data[0] ^ data[2] ^ data[4] ^ data[5]);
