module mg_06041 (input CLK,input RESETn,input [1:0] senceMask,input signalIn,output reg signalOut);
parameter MASK_LOW = 2'b00, 
  MASK_ANY = 2'b01, 
  MASK_FALL = 2'b10, 
  MASK_RIZE = 2'b11; 
  parameter S_RESET = 0, 
  S_INIT0 = 1, 
  S_INIT1 = 2, 
  S_WORK = 3; 
  reg [ 1 : 0 ] State, Next; 
  reg [ 1 : 0 ] signal; 
  always @ (posedge CLK) 
  if(~RESETn) 
  State <= S_INIT0; 
  else 
  State <= Next; 
  always @ (posedge CLK) 
  case(State) 
  S_RESET : signal <= 2'b0; 
  default : signal <= { signal[0], signalIn }; 
  endcase 
  always @ (*) begin 
  case (State) 
  S_RESET : Next = S_INIT0; 
  S_INIT0 : Next = S_INIT1; 
  default : Next = S_WORK; 
  endcase 
  case( { State, senceMask } ) 
  { S_WORK, MASK_LOW } : signalOut = ~signal[1] & ~signal[0]; 
  { S_WORK, MASK_ANY } : signalOut = signal[1] ^ signal[0]; 
  { S_WORK, MASK_FALL } : signalOut = signal[1] & ~signal[0]; 
  { S_WORK, MASK_RIZE } : signalOut = ~signal[1] & signal[0]; 
  default : signalOut = 1'b0; 
  endcase 
  end 
 endmodule

