            d_a <= ram[addr_a];
        end
    end

    // Port B: Read only
    always @(posedge clk_b or posedge reset) begin
        if (reset) begin
            d_b <= 4'b0000;
        end else begin
            d_b <= ram[addr_b];
        end
    end

    // Output assignments
    always @(*) begin
        dout_a = d_a;
        dout_b = d_b;
    end

    // Initialize RAM for simulation
    `ifdef SIMULATION
        integer i;
        initial begin
            for (i = 0; i < 16; i = i + 1) begin
                ram[i] = 4'b0000;
            end
        end
    `endif

