module autovcoder_073694 (
    SW,
    KEY,
    LEDR,
    CLOCK_50
);

  input [9:0] SW;
  input [2:0] KEY;
  input CLOCK_50;
  output [9:0] LEDR;

  wire clear1, Enable;
  wire resetm;
  wire [2:0] LetSelect;
  wire MorseOut;
  reg [10:0] LettersIn;
  wire muxS;

  reg [24:0] count1;


  assign resetm = ~KEY[0];
  assign muxS = ~KEY[1];
  assign LetSelect = SW[2:0];
  assign LEDR[0] = MorseOut;

  always @(posedge CLOCK_50) begin
    if ((clear1 == 1'b1) | (resetm == 1'b1)) count1 <= 25'd0;
    else count1 <= count1 + 1'b1;
  end

  assign clear1 = Enable;
  assign Enable = (count1 == 25'd25000000) ? 1'b1 : 1'b0;

  always @(*) begin
    case (LetSelect)
      3'b000:  LettersIn = 11'b10111000000;
      3'b001:  LettersIn = 11'b11101010100;
      3'b010:  LettersIn = 11'b11101011101;
      3'b011:  LettersIn = 11'b11101010000;
      3'b100:  LettersIn = 11'b10000000000;
      3'b101:  LettersIn = 11'b10101110100;
      3'b110:  LettersIn = 11'b11101110100;
      3'b111:  LettersIn = 11'b10101010000;
      default: LettersIn = 11'b00000000000;
    endcase
  end

  MorseCode mainBlock (
      .muxSel (muxS),
      .Letters(LettersIn),
      .MorseO (MorseOut),
      .clock  (Enable),
      .reset  (resetm)
  );

endmodule

