module mg_03709(clk,rst_n,bps_start,clk_bps,RS232_rx,rx_data,rx_int,data_out);
input clk; 
  input rst_n; 
  input RS232_rx; 
  input clk_bps; 
  output bps_start; 
  output [7:0] rx_data; 
  output rx_int; 
  output reg [7:0]data_out; 
  reg RS232_rx0,RS232_rx1,RS232_rx2,RS232_rx3; 
  wire neg_RS232_rx; 
  always @(posedge clk or negedge rst_n) begin 
  if(!rst_n) begin 
  RS232_rx0 <= 1'b0; 
  RS232_rx1 <= 1'b0; 
  RS232_rx2 <= 1'b0; 
  RS232_rx3 <= 1'b0; 
  end 
  else begin 
  RS232_rx0 <= RS232_rx; 
  RS232_rx1 <= RS232_rx0; 
  RS232_rx2 <= RS232_rx1; 
  RS232_rx3 <= RS232_rx2; 
  end 
  end 
  assign neg_RS232_rx = RS232_rx3 & RS232_rx2 & ~RS232_rx1 & ~RS232_rx0; 
  reg bps_start_r; 
  reg [3:0] num; 
  reg rx_int; 
  always @(posedge clk or negedge rst_n) 
  if(!rst_n) begin 
  bps_start_r <=1'bz; 
  rx_int <= 1'b0; 
  end 
  else if(neg_RS232_rx) begin 
  bps_start_r <= 1'b1; 
  rx_int <= 1'b1; 
  end 
  else if(num==4'd12) begin 
  bps_start_r <=1'b0; 
  rx_int <= 1'b0; 
  end 
  assign bps_start = bps_start_r; 
  reg [7:0] rx_data_r; 
  reg [7:0] rx_temp_data; 
  always @(posedge clk or negedge rst_n) 
  if(!rst_n) begin 
  rx_temp_data <= 8'd0; 
  num <= 4'd0; 
  rx_data_r <= 8'd0; 
  end 
  else if(rx_int) begin 
  if(clk_bps) begin 
  num <= num+1'b1; 
  case(num) 
  4'd1: rx_temp_data[0] <= RS232_rx; 
  4'd2: rx_temp_data[1] <= RS232_rx; 
  4'd3: rx_temp_data[2] <= RS232_rx; 
  4'd4: rx_temp_data[3] <= RS232_rx; 
  4'd5: rx_temp_data[4] <= RS232_rx; 
  4'd6: rx_temp_data[5] <= RS232_rx; 
  4'd7: rx_temp_data[6] <= RS232_rx; 
  4'd8: rx_temp_data[7] <= RS232_rx; 
  default: ; 
  endcase 
  data_out <= rx_temp_data; 
  end 
  else if(num==4'd12) begin 
  num <= 4'd0; 
  rx_data_r <= rx_temp_data; 
  end 
  end 
  assign rx_data = rx_data_r; 
 endmodule

