  assign ftdi_be   = ftdi_oe_n ? BE_HIGHZ : ftdi_r_be;




  initial begin
    ftdi_rxf_n <= 1'b1;
    while (1) begin
      repeat (randuint(1, 100)) @(posedge ftdi_clk);
      ftdi_rxf_n <= 1'b0;
      repeat (randuint(1, 100)) @(posedge ftdi_clk);
      ftdi_rxf_n <= 1'b1;
    end
  end


  initial begin
    ftdi_txe_n <= 1'b1;
    while (1) begin
      repeat (randuint(1, 100)) @(posedge ftdi_clk);
      ftdi_txe_n <= 1'b0;
