module autovcoder_101199 (
    address,
    sout
);

  input [5:0] address;
  output reg [3:0] sout;

  wire [1:0] row;
  wire [3:0] col;

  assign row = {address[5], address[0]};
  assign col = address[4:1];

  always @(address) begin
    case (row)

      0:
      case (col)
        0:  sout = 7;
        1:  sout = 13;
        2:  sout = 14;
        3:  sout = 3;
        4:  sout = 0;
        5:  sout = 6;
        6:  sout = 9;
        7:  sout = 10;
        8:  sout = 1;
        9:  sout = 2;
        10: sout = 8;
        11: sout = 5;
        12: sout = 11;
        13: sout = 12;
        14: sout = 4;
        15: sout = 15;
      endcase

      1:
      case (col)
        0:  sout = 13;
        1:  sout = 8;
        2:  sout = 11;
        3:  sout = 5;
        4:  sout = 6;
        5:  sout = 15;
