module rtlpp_04549 (
  input wire clk,
  input wire [23:0] data_in,
  output reg address_out,
  output wire spdif_out
);

parameter integer C_clk_freq = 25000000;
parameter integer C_sample_freq = 48000;
parameter integer C_phase_accu_bits = 24;
parameter integer C_phase_increment = (C_sample_freq * (2 ** (C_phase_accu_bits - 3))) / C_clk_freq;

reg [C_phase_accu_bits-1:0] R_phase_accu = 0;
reg [1:0] R_clkdiv_shift = 2'b0;
reg [23:0] data_in_buffer = 24'b0;
reg [5:0] bit_counter = 6'b0;
reg [8:0] frame_counter = 9'b0;
reg data_biphase = 1'b0;
reg [7:0] data_out_buffer = 8'b0;
reg parity = 1'b0;
reg [23:0] channel_status_shift = 24'b0;
wire [23:0] channel_status = 24'b001000000000000001000000;

always @(posedge clk) begin
  R_phase_accu <= R_phase_accu + C_phase_increment;
  R_clkdiv_shift <= {R_clkdiv_shift[0], R_phase_accu[C_phase_accu_bits-1]};
end

always @(posedge clk) begin
  if (R_clkdiv_shift == 2'b01) begin
    bit_counter <= bit_counter + 1;
  end
