module origen_130733 (
    input [254:0] in,
    output [7:0] count
);

    wire [254:0] stage1;
    wire [169:0] stage2;
    wire [113:0] stage3;
    wire [75:0] stage4;
    wire [50:0] stage5;
    wire [33:0] stage6;
    wire [22:0] stage7;
    wire [15:0] stage8;
    wire [10:0] stage9;
    wire [7:0] stage10;

    // Stage 1: 3-bit adders
    genvar i;
    generate
        for (i = 0; i < 85; i = i + 1) begin : stage1_adders
            assign stage1[3*i+2:3*i] = in[3*i] + in[3*i+1] + in[3*i+2];
        end
    endgenerate

    // Handle remaining bits
    assign stage1[254] = in[254];
    assign stage1[253] = in[253];

    // Stage 2: 3-bit adders
    generate
        for (i = 0; i < 56; i = i + 1) begin : stage2_adders
            assign stage2[3*i+2:3*i] = stage1[3*i] + stage1[3*i+1] + stage1[3*i+2];
        end
    endgenerate

    // Handle remaining bits
    assign stage2[168:168] = stage1[254:254];
    assign stage2[167:166] = stage1[253:252];

    // Stage 3: 3-bit adders
    generate
        for (i = 0; i < 37; i = i + 1) begin : stage3_adders
            assign stage3[3*i+2:3*i] = stage2[3*i] + stage2[3*i+1] + stage2[3*i+2];
        end
    endgenerate

    // Handle remaining bits
    assign stage3[113:111] = stage2[168:166];
    assign stage3[110] = stage2[165];

    // Stage 4: 3-bit adders
    generate
        for (i = 0; i < 25; i = i + 1) begin : stage4_adders
            assign stage4[3*i+2:3*i] = stage3[3*i] + stage3[3*i+1] + stage3[3*i+2];
        end
    endgenerate

    // Handle remaining bits
    assign stage4[75:73] = stage3[113:111];

    // Stage 5: 3-bit adders
    generate
        for (i = 0; i < 16; i = i + 1) begin : stage5_adders
            assign stage5[3*i+2:3*i] = stage4[3*i] + stage4[3*i+1] + stage4[3*i+2];
        end
    endgenerate

    // Handle remaining bits
    assign stage5[50:48] = stage4[75:73];
    assign stage5[47] = stage4[72];

    // Stage 6: 3-bit adders
    generate
        for (i = 0; i < 11; i = i + 1) begin : stage6_adders
            assign stage6[3*i+2:3*i] = stage5[3*i] + stage5[3*i+1] + stage5[3*i+2];
        end
    endgenerate

    // Handle remaining bit
    assign stage6[33] = stage5[50];

    // Stage 7: 3-bit adders
    generate
        for (i = 0; i < 7; i = i + 1) begin : stage7_adders
            assign stage7[3*i+2:3*i] = stage6[3*i] + stage6[3*i+1] + stage6[3*i+2];
        end
    endgenerate

    // Handle remaining bits
    assign stage7[22:21] = stage6[33:32];

    // Stage 8: 3-bit adders
    generate
        for (i = 0; i < 5; i = i + 1) begin : stage8_adders
            assign stage8[3*i+2:3*i] = stage7[3*i] + stage7[3*i+1] + stage7[3*i+2];
        end
    endgenerate

    // Handle remaining bit
    assign stage8[15] = stage7[22];

    // Stage 9: 3-bit adders
    generate
        for (i = 0; i < 3; i = i + 1) begin : stage9_adders
            assign stage9[3*i+2:3*i] = stage8[3*i] + stage8[3*i+1] + stage8[3*i+2];
        end
    endgenerate

    // Handle remaining bits
    assign stage9[10:9] = stage8[15:14];

    // Stage 10: Final addition
    assign stage10 = stage9[2:0] + stage9[5:3] + stage9[8:6] + stage9[10:9];

    // Output assignment
    assign count = stage10;

endmodule

