// Gate-level modules
module origen_048723(input [1:0] a, output [1:0] y);
  assign y = ~a;
endmodule

module andgate(input [1:0] a, input [1:0] b, output [1:0] y);
  assign y = a & b;
endmodule

module orgate(input [1:0] a, input [1:0] b, output [1:0] y);
  assign y = a | b;
endmodule

module xorgate(input [1:0] a, input [1:0] b, output [1:0] y);
  assign y = a ^ b;
endmodule

// Main module
module test_f4(input [1:0] x, input [1:0] y, input [1:0] c1, input [1:0] c2, output [1:0] s);
  wire [1:0] s1, s2, s3, s4, s5, s6, s7;

  orgate or1(.a(x), .b(y), .y(s7));
  xorgate xor1(.a(x), .b(y), .y(s6));
  xorgate xor2(.a(c2), .b(s7), .y(s4));
  xorgate xor3(.a(c2), .b(s6), .y(s5));
  notgate not1(.a(c1), .y(s3));
  andgate and1(.a(s3), .b(s4), .y(s1));
  andgate and2(.a(s5), .b(c1), .y(s2));
  orgate or2(.a(s1), .b(s2), .y(s));
endmodule

// Test bench
module testbench;
  reg [1:0] x, y, c1, c2;
  wire [1:0] s;

  test_f4 uut(.x(x), .y(y), .c1(c1), .c2(c2), .s(s));

  initial begin
    $monitor("Time=%0t x=%b y=%b c1=%b c2=%b s=%b", $time, x, y, c1, c2, s);

    // Initial values
    x = 2'b00; y = 2'b00; c1 = 2'b00; c2 = 2'b00;
    #10;

    // Test 1
    x = 2'b00; y = 2'b00; c1 = 2'b01; c2 = 2'b10;
    #10;

    // Test 2
    x = 2'b00; y = 2'b11; c1 = 2'b11; c2 = 2'b00;
    #10;

    // Test 3
    x = 2'b11; y = 2'b00; c1 = 2'b10; c2 = 2'b01;
    #10;

    // Test 4
    x = 2'b11; y = 2'b11; c1 = 2'b00; c2 = 2'b11;
    #10;

    $finish;
  end
endmodule

