        if (!rst_n)
            cnt_hsync <= 3'd0;
        else if (trig)
            cnt_hsync <= Thsynccnt;
        else if (ena & done)
            cnt_hsync <= cnt_hsync - 1'b1;

    always @(posedge clk or negedge rst_n)
        if (!rst_n)
            hsync <= 1'b0;
        else
            hsync <= sync;

    always @(posedge clk or negedge rst_n)
