end

always @(outx or outy or decrypt_i)
begin
	outmux = (decrypt_i ? outy : outx);
end

always @(posedge clk or negedge reset)
begin
	if(!reset) begin
		data_reg = 0;
		state = 0;
		ready_o = 0;
		data_o_reg = 0;
	end else begin
		data_reg = next_data_reg;
		state = next_state;
		ready_o = next_ready_o;
		data_o_reg = next_data_o;
