    output reg [1:0] m_axi_rready
);

// Internal logic for handling signals will go here

always @(posedge aclk or negedge aresetn) begin
    if (!aresetn) begin
        // Reset logic
        s_axi_awready <= 1'b0;
        s_axi_wready <= 1'b0;
        s_axi_bresp <= 2'b00;
        s_axi_bvalid <= 1'b0;
        s_axi_arready <= 1'b0;
        s_axi_rdata <= 32'b0;
        s_axi_rresp <= 2'b00;
        s_axi_rvalid <= 1'b0;
        m_axi_awaddr <= 64'b0;
        m_axi_awprot <= 6'b0;
        m_axi_awvalid <= 2'b0;
        m_axi_wdata <= 64'b0;
        m_axi_wstrb <= 8'b0;
        m_axi_wvalid <= 2'b0;
        m_axi_bready <= 2'b0;
        m_axi_araddr <= 64'b0;
        m_axi_arprot <= 6'b0;
        m_axi_arvalid <= 2'b0;
        m_axi_rready <= 2'b0;
