            m_axi_awaddr <= {s_axi_awaddr, s_axi_awaddr + 32}; // Example transformation
            m_axi_awprot <= {s_axi_awprot, s_axi_awprot};
            m_axi_awvalid <= 2'b11;
        end else if (m_axi_awready == 2'b11) begin
            s_axi_awready <= 1'b0;
            m_axi_awvalid <= 2'b0;
        end

        if (s_axi_wvalid && !s_axi_wready) begin
            s_axi_wready <= 1'b1;
            m_axi_wdata <= {s_axi_wdata, s_axi_wdata + 32}; // Example transformation
            m_axi_wstrb <= {s_axi_wstrb, s_axi_wstrb};
            m_axi_wvalid <= 2'b11;
        end else if (m_axi_wready == 2'b11) begin
            s_axi_wready <= 1'b0;
            m_axi_wvalid <= 2'b0;
        end

        if (m_axi_bvalid && m_axi_bready == 2'b11) begin
            s_axi_bresp <= m_axi_bresp[1:0];
            s_axi_bvalid <= 1'b1;
        end else if (s_axi_bready && s_axi_bvalid) begin
            s_axi_bvalid <= 1'b0;
        end

        if (s_axi_arvalid && !s_axi_arready) begin
            s_axi_arready <= 1'b1;
            m_axi_araddr <= {s_axi_araddr, s_axi_araddr + 32}; // Example transformation
            m_axi_arprot <= {s_axi_arprot, s_axi_arprot};
            m_axi_arvalid <= 2'b11;
        end else if (m_axi_arready == 2'b11) begin
            s_axi_arready <= 1'b0;
            m_axi_arvalid <= 2'b0;
        end

        if (m_axi_rvalid && m_axi_rready == 2'b11) begin
            s_axi_rdata <= m_axi_rdata[31:0];
            s_axi_rresp <= m_axi_rresp[1:0];
            s_axi_rvalid <= 1'b1;
        end else if (s_axi_rready && s_axi_rvalid) begin
            s_axi_rvalid <= 1'b0;
        end

        m_axi_bready <= 2'b11;
        m_axi_rready <= 2'b11;
    end
end

