  always @(posedge clk or negedge reset_n)
  begin
    if (reset_n == 0)
      readdata <= 0;
    else if (clk_en)
      readdata <= read_mux_out;
  end

  assign data_in = in_port;

  always @(posedge clk or negedge reset_n)
  begin
    if (reset_n == 0)
      irq_mask <= 0;
    else if (chipselect && ~write_n && (address == 2))
      irq_mask <= writedata[3:0];
  end

  assign irq = |(edge_capture & irq_mask);
  assign edge_capture_wr_strobe = chipselect && ~write_n && (address == 3);

  always @(posedge clk or negedge reset_n)
  begin
    if (reset_n == 0)
      edge_capture[0] <= 0;
    else if (clk_en)
    begin
      if (edge_capture_wr_strobe)
        edge_capture[0] <= 0;
      else if (edge_detect[0])
        edge_capture[0] <= -1;
    end
  end

  always @(posedge clk or negedge reset_n)
  begin
    if (reset_n == 0)
      edge_capture[1] <= 0;
    else if (clk_en)
    begin
      if (edge_capture_wr_strobe)
        edge_capture[1] <= 0;
      else if (edge_detect[1])
        edge_capture[1] <= -1;
    end
  end

  always @(posedge clk or negedge reset_n)
  begin
    if (reset_n == 0)
      edge_capture[2] <= 0;
    else if (clk_en)
    begin
      if (edge_capture_wr_strobe)
        edge_capture[2] <= 0;
      else if (edge_detect[2])
        edge_capture[2] <= -1;
    end
  end

  always @(posedge clk or negedge reset_n)
  begin
    if (reset_n == 0)
      edge_capture[3] <= 0;
    else if (clk_en)
    begin
      if (edge_capture_wr_strobe)
        edge_capture[3] <= 0;
      else if (edge_detect[3])
        edge_capture[3] <= -1;
    end
  end

  always @(posedge clk or negedge reset_n)
  begin
    if (reset_n == 0)
    begin
      d1_data_in <= 0;
      d2_data_in <= 0;
    end
    else if (clk_en)
    begin
      d1_data_in <= data_in;
      d2_data_in <= d1_data_in;
    end
  end

  assign edge_detect = ~d1_data_in & d2_data_in;

