module rtlpp_11645 (
  input                 clk,
  input                 reset,
  input       [15:0]    data,
  input                 data_valid,
  input       [1:0]     trigger_i,
  input                 trigger_in,
  input       [17:0]    edge_detect_enable,
  input       [17:0]    rise_edge_enable,
  input       [17:0]    fall_edge_enable,
  input       [17:0]    low_level_enable,
  input       [17:0]    high_level_enable,
  input       [6:0]     trigger_logic,
  output  reg           trigger_out,
  output  reg           trigger_out_adc
);

  reg     [1:0]   ext_t_m;
  reg     [1:0]   ext_t_low_level_hold;
  reg     [1:0]   ext_t_high_level_hold;
  reg     [1:0]   ext_t_edge_detect_hold;
  reg     [1:0]   ext_t_rise_edge_hold;
  reg     [1:0]   ext_t_fall_edge_hold;
  reg             ext_t_low_level_ack;
  reg             ext_t_high_level_ack;
  reg             ext_t_edge_detect_ack;
  reg             ext_t_rise_edge_ack;
  reg             ext_t_fall_edge_ack;
  reg     [15:0]  data_m1;
  reg     [15:0]  low_level;
  reg     [15:0]  high_level;
  reg     [15:0]  edge_detect;
  reg     [15:0]  rise_edge;
  reg     [15:0]  fall_edge;
  reg     [15:0]  low_level_m;
  reg     [15:0]  high_level_m;
  reg     [15:0]  edge_detect_m;
  reg     [15:0]  rise_edge_m;
  reg     [15:0]  fall_edge_m;
  reg             trigger_active;
  reg             trigger_active_mux;
  reg             trigger_active_d1;

  always @(posedge clk) begin
    if (data_valid == 1'b1) begin
      trigger_active_d1 <= trigger_active_mux;
      trigger_out <= trigger_active_d1;
      trigger_out_adc <= trigger_active_mux;
    end
  end

  always @(posedge clk) begin
    if (data_valid == 1'b1) begin
      case (trigger_logic[0])
        0: trigger_active = |(({ext_t_edge_detect_hold, edge_detect_m} & edge_detect_enable) |
                              ({ext_t_rise_edge_hold,   rise_edge_m}   & rise_edge_enable) |
                              ({ext_t_fall_edge_hold,   fall_edge_m}   & fall_edge_enable) |
                              ({ext_t_low_level_hold,   low_level_m}   & low_level_enable) |
                              ({ext_t_high_level_hold , high_level_m}  & high_level_enable));
        1: trigger_active = &(({ext_t_edge_detect_hold, edge_detect_m} | ~edge_detect_enable) &
                              ({ext_t_rise_edge_hold,   rise_edge_m}   | ~rise_edge_enable) &
                              ({ext_t_fall_edge_hold,   fall_edge_m}   | ~fall_edge_enable) &
                              ({ext_t_low_level_hold,   low_level_m}   | ~low_level_enable) &
                              ({ext_t_high_level_hold , high_level_m}  | ~high_level_enable));
        default: trigger_active = 1'b1;
      endcase
    end
  end

  always @(*) begin
    case (trigger_logic[6:4])
      3'd0: trigger_active_mux = trigger_active;
      3'd1: trigger_active_mux = trigger_in;
      3'd2: trigger_active_mux = trigger_active & trigger_in;
      3'd3: trigger_active_mux = trigger_active | trigger_in;
      3'd4: trigger_active_mux = trigger_active ^ trigger_in;
      3'd7: trigger_active_mux = 1'b0; 
      default: trigger_active_mux = 1'b0;
    endcase
  end

  always @(posedge clk) begin
    if (reset == 1'b1) begin
      data_m1 <= 16'd0;
      edge_detect <= 16'd0;
      rise_edge <= 16'd0;
      fall_edge <= 16'd0;
      low_level <= 16'd0;
      high_level <= 16'd0;
    end else begin
      if (data_valid == 1'b1) begin
        data_m1 <=  data;
        edge_detect <=  data_m1 ^ data;
        rise_edge   <= (data_m1 ^ data) & data;
        fall_edge   <= (data_m1 ^ data) & ~data;
        low_level   <= ~data;
        high_level  <= data;
        edge_detect_m <= edge_detect;
        rise_edge_m   <= rise_edge;
        fall_edge_m   <= fall_edge;
        low_level_m   <= low_level;
        high_level_m  <= high_level;
      end
    end
  end

  always @(posedge clk) begin
    if (reset == 1'b1) begin
      ext_t_m <= 2'd0;
      ext_t_edge_detect_hold <= 2'd0;
      ext_t_rise_edge_hold <= 2'd0;
      ext_t_fall_edge_hold <= 2'd0;
      ext_t_low_level_hold <= 2'd0;
      ext_t_high_level_hold <= 2'd0;
    end else begin
      ext_t_m <=  trigger_i;
      ext_t_edge_detect_hold <= ext_t_edge_detect_ack ? 2'b0 : (ext_t_m ^ trigger_i) | ext_t_edge_detect_hold;
      ext_t_rise_edge_hold   <= ext_t_rise_edge_ack   ? 2'b0 : ((ext_t_m ^ trigger_i) & trigger_i) | ext_t_rise_edge_hold;
      ext_t_fall_edge_hold   <= ext_t_fall_edge_ack   ? 2'b0 : ((ext_t_m ^ trigger_i) & ~trigger_i) | ext_t_fall_edge_hold;
      ext_t_low_level_hold   <= ext_t_low_level_ack   ? 2'b0 : (~trigger_i) | ext_t_low_level_hold;
      ext_t_high_level_hold  <= ext_t_high_level_ack  ? 2'b0 : (trigger_i) | ext_t_high_level_hold;
      ext_t_edge_detect_ack <= data_valid & (|ext_t_edge_detect_hold);
      ext_t_rise_edge_ack   <= data_valid & (|ext_t_rise_edge_hold);
      ext_t_fall_edge_ack   <= data_valid & (|ext_t_fall_edge_hold);
      ext_t_low_level_ack   <= data_valid & (|ext_t_low_level_hold);
      ext_t_high_level_ack  <= data_valid & (|ext_t_high_level_hold);
    end
  end

endmodule

files.origen_042822.v:
module origen_042822(
    input [5:0] opcode,
    output reg RegDst,
    output reg ALUSrc,
    output reg MemtoReg,
    output reg RegWrite,
    output reg MemRead,
    output reg MemWrite,
    output reg Branch,
    output reg Jump,
    output reg [1:0] ALUOp,
    output reg BneDst,
    output reg ExtndDst
);

always @(*) begin
    case(opcode)
        6'b000000: begin // R-Format
            RegDst = 1'b1;
            ALUSrc = 1'b0;
            MemtoReg = 1'b0;
            RegWrite = 1'b1;
            MemRead = 1'b0;
            MemWrite = 1'b0;
            Branch = 1'b0;
            Jump = 1'b0;
            ALUOp = 2'b10;
            BneDst = 1'b0;
            ExtndDst = 1'b0;
        end
        6'b100011: begin // LW
            RegDst = 1'b0;
            ALUSrc = 1'b1;
            MemtoReg = 1'b1;
            RegWrite = 1'b1;
            MemRead = 1'b1;
            MemWrite = 1'b0;
            Branch = 1'b0;
            Jump = 1'b0;
            ALUOp = 2'b00;
            BneDst = 1'b0;
            ExtndDst = 1'b1;
        end
        6'b101011: begin // SW
            RegDst = 1'bx;
            ALUSrc = 1'b1;
            MemtoReg = 1'bx;
            RegWrite = 1'b0;
            MemRead = 1'b0;
            MemWrite = 1'b1;
            Branch = 1'b0;
            Jump = 1'b0;
            ALUOp = 2'b00;
            BneDst = 1'b0;
            ExtndDst = 1'b1;
        end
        6'b000100: begin // BEQ
            RegDst = 1'bx;
            ALUSrc = 1'b0;
            MemtoReg = 1'bx;
            RegWrite = 1'b0;
            MemRead = 1'b0;
            MemWrite = 1'b0;
            Branch = 1'b1;
            Jump = 1'b0;
            ALUOp = 2'b01;
            BneDst = 1'b0;
            ExtndDst = 1'b1;
        end
        6'b000010: begin // J
            RegDst = 1'bx;
            ALUSrc = 1'bx;
            MemtoReg = 1'bx;
            RegWrite = 1'b0;
            MemRead = 1'b0;
            MemWrite = 1'b0;
            Branch = 1'b0;
            Jump = 1'b1;
            ALUOp = 2'bxx;
            BneDst = 1'b0;
            ExtndDst = 1'b0;
        end
        6'b000101: begin // BNE
            RegDst = 1'bx;
            ALUSrc = 1'b0;
            MemtoReg = 1'bx;
            RegWrite = 1'b0;
            MemRead = 1'b0;
            MemWrite = 1'b0;
            Branch = 1'b1;
            Jump = 1'b0;
            ALUOp = 2'b01;
            BneDst = 1'b1;
            ExtndDst = 1'b1;
        end
        6'b001101: begin // ORI
            RegDst = 1'b0;
            ALUSrc = 1'b1;
            MemtoReg = 1'b0;
            RegWrite = 1'b1;
            MemRead = 1'b0;
            MemWrite = 1'b0;
            Branch = 1'b0;
            Jump = 1'b0;
            ALUOp = 2'b11;
            BneDst = 1'b0;
            ExtndDst = 1'b0;
        end
        default: begin
            RegDst = 1'bx;
            ALUSrc = 1'bx;
            MemtoReg = 1'bx;
            RegWrite = 1'b0;
            MemRead = 1'b0;
            MemWrite = 1'b0;
            Branch = 1'b0;
            Jump = 1'b0;
            ALUOp = 2'bxx;
            BneDst = 1'b0;
            ExtndDst = 1'b0;
            $display("Error: Unimplemented opcode %b", opcode);
        end
    endcase
end

endmodule

files.conformal_rtl_origen_042822.do:
// Conformal LEC RTL vs RTL: combinational equivalence (no netlist, no technology library).
// Golden and revised in ./rtl/golden.v, ./rtl/revised.v.
// Uses -SystemVerilog for SV support (logic, always_comb, int, $bits, etc); backward compatible with Verilog.
// NOTE: Conformal uses // for comments. Do NOT use # (Conformal treats # as a command and aborts).

set undefined cell black_box
read design ./rtl/golden.v -SystemVerilog -Golden
read design ./rtl/revised.v -SystemVerilog -Revised

// Switch to LEC mode and compare
set system mode lec
add compared points -all
compare
exit -force

