module rtlpp_02374
(
  input                                clk,
  input                                reset_n,

  input                                stall,

  input  [31:0]                        a_decode,
  input  [31:0]                        b_decode,

  input  [31:0]                        offset_decode,

  input   [4:0]                        a_rs_idx,
  input   [4:0]                        b_rs_idx,

  input   [4:0]                        regfile_rd_idx,
  input  [31:0]                        regfile_rd_val,

  input  [31:0]                        pc_in,
  input   [4:0]                        rd_in,
  input                                branch_in,
  input                                jump_in,
  input                                system_in,
  input                                load_in,
  input                                store_in,
  input   [2:0]                        ld_store_width,
  input                                cancelled,

  input                                add_nsub,
  input                                arith,

  input                                cmp_unsigned,
  input                                cmp_is_lt,
  input                                cmp_is_ge,
  input                                cmp_is_eq,
  input                                cmp_is_ne,

  input                                bit_is_and,
  input                                bit_is_or,
  input                                bit_is_xor,

  input                                shift_arith,
  input                                shift_left,
  input                                shift_right,

  input                                extm_update_rd,
  input       [4:0]                    extm_rd_idx,
  input      [31:0]                    extm_rd_val,

  input                                clr_load_op,
  output reg  [4:0]                    rd,
  output reg                           update_pc,
  output reg                           load,
  output reg                           store,

  output reg [31:0]                    pc,
  output reg [31:0]                    c,

  output reg [31:0]                    addr,
  output reg  [3:0]                    st_be,
  input      [31:0]                    ld_data,

  output reg                           retired_instr,

  output                               misaligned_load,
  output                               misaligned_store,
  output     [31:0]                    misaligned_addr
);

reg           [2:0]                    ld_width;

reg           [1:0]                    addr_lo;

wire        [31:0] a                   = (a_rs_idx == regfile_rd_idx && regfile_rd_idx != 5'h0) ? regfile_rd_val : a_decode;
wire        [31:0] b                   = (b_rs_idx == regfile_rd_idx && regfile_rd_idx != 5'h0) ? regfile_rd_val : b_decode;

wire        [31:0] add                 = a + b;
wire        [31:0] sub                 = a - b;
wire        [31:0] add_sub             = add_nsub ? add : sub;

wire signed [31:0] a_signed            = a;
wire signed [31:0] b_signed            = b;

wire               lt_unsigned         = (a        <  b);
wire               ge                  = (a_signed >= b_signed);
wire               ge_unsigned         = (a        >= b);
wire               eq                  = (a_signed == b_signed);
wire        [31:0] cmp                 = {31'h0, (cmp_is_eq & eq) | (cmp_is_ne & ~eq) |
                                                 (cmp_is_ge & ~cmp_unsigned &  ge)    | (cmp_is_ge & cmp_unsigned & ge_unsigned) |
                                                 (cmp_is_lt & ~cmp_unsigned & ~ge)    | (cmp_is_lt & cmp_unsigned & lt_unsigned)};

wire        [31:0] andop               = a & b;
wire        [31:0] orop                = a | b;
wire        [31:0] xorop               = a ^ b;

wire        [31:0] bitop               = ({32{bit_is_and}} & andop) | ({32{bit_is_or}} & orop) | ({32{bit_is_xor}} & xorop);

wire        [31:0] sll                 = a        <<  b[4:0];
wire        [31:0] srl                 = a        >>  b[4:0];
wire        [31:0] sra                 = a_signed >>> b[4:0];

wire        [31:0] shift               = ({32{shift_left}}                 & sll) |
                                         ({32{shift_right & ~shift_arith}} & srl) |
                                         ({32{shift_right &  shift_arith}} & sra);

wire               branch_taken        = branch_in & cmp[0];

wire        [31:0] next_pc             = (jump_in | system_in) ? add :
                                                                 pc_in + offset_decode;

wire         [4:0] next_rd             = extm_update_rd ? extm_rd_idx :
                                         stall          ? rd          :
                                                          ((~update_pc & ~((jump_in | branch_taken) & |next_pc[1:0])) ? rd_in : 5'h0);

wire        [31:0] next_addr           = a + offset_decode;

wire               addr_is_misaligned  = (load_in | store_in) & ((ld_store_width[0] & next_addr[0]) | (ld_store_width[1] & |next_addr[1:0])) & ~load;

assign             misaligned_store    = store_in & addr_is_misaligned;
assign             misaligned_load     = load_in  & addr_is_misaligned;
assign             misaligned_addr     = next_addr;

wire        [31:0] ld_data_shift = ld_data >> {addr_lo, 3'b000};

always @(posedge clk or negedge reset_n)
begin
  if (!reset_n)
  begin
    rd                                 <= 5'h0;
    load                               <= 1'b0;
    store                              <= 1'b0;
    update_pc                          <= 1'b0;
    ld_width                           <= 3'b000;
    retired_instr                      <= 1'b0;
  end
  else
  begin
    retired_instr                      <= ~stall & ~cancelled;

    if (extm_update_rd)
    begin
      c                                <= extm_rd_val;
    end
    else if (load)
    begin
      c                                <= (ld_data_shift & {{16{ld_width[1]}}, {8{|ld_width[1:0]}}, 8'hff}) |
                                          {{16{~ld_width[2] & ~ld_width[1] &  ld_width[0] & ld_data_shift[15]}}, 16'h0} |
                                          {{24{~ld_width[2] & ~ld_width[1] & ~ld_width[0] & ld_data_shift[7]}}, 8'h0};
    end
    else if (arith)
    begin
      c                                <= add_sub;
    end
    else if (bit_is_and | bit_is_or | bit_is_xor)
    begin
      c                                <= bitop;
    end
    else if (cmp_is_lt | cmp_is_ge | cmp_is_eq | cmp_is_ne)
    begin
      c                                <= cmp;
    end
    else if (shift_left | shift_right)
    begin
      c                                <= shift;
    end
    else if (jump_in)
    begin
      c                                <= pc_in + 32'h4;
    end
    else if (store_in)
    begin
      c                                <= b << {next_addr[1:0] & {~ld_store_width[1], ~ld_store_width[0]}, 3'b000};
    end

    if (load_in | store_in)
    begin
      addr                             <= stall ? addr          : {next_addr[31:2], 2'b00};
      addr_lo                          <= stall ? addr_lo [1:0] : next_addr[1:0];
    end

    rd                                 <= next_rd;
    pc                                 <= stall ? pc : next_pc;
    update_pc                          <= stall ? update_pc : ((jump_in | system_in | branch_taken) & ~update_pc);

    load                               <= (stall ? load : (load_in  & ~update_pc)) & ~clr_load_op & ~misaligned_load;
    store                              <= store_in & ~update_pc & ~misaligned_store;

    st_be                              <= ld_store_width[1] ? 4'b1111 :
                                          ld_store_width[0] ? (4'b0011 << {next_addr[1], 1'b0}):
                                                              (4'b0001 <<  next_addr[1:0]);

    ld_width                           <= stall ? ld_width : ld_store_width;
  end
end

endmodule

files.origen_006348.v:
module origen_006348 (
    input wire SCLK,
    input wire RESET,
    input wire RX,
    input wire TX_VALID,
    input wire [7:0] TX_DATA_IN,
    output reg RX_VALID,
    output reg RX_PARITY,
    output reg [7:0] RX_DATA_OUT,
    output reg TX,
    output reg TX_READY
);

    // Parameters
    parameter CLOCK_RATE = 50000000;  // 50 MHz system clock
    parameter BAUD_RATE = 115200;     // 115200 bps
    parameter PARITY_ENABLED = 1;     // 1 for enabled, 0 for disabled
    parameter PARITY_ODD = 1;         // 1 for odd parity, 0 for even parity

    // Constants
    localparam UART_CLK_DIVIDER = CLOCK_RATE / (BAUD_RATE * 8) - 1;
    localparam RX_IDLE = 2'b00, RX_START = 2'b01, RX_DATA = 2'b10, RX_STOP = 2'b11;
    localparam TX_IDLE = 2'b00, TX_START = 2'b01, TX_DATA = 2'b10, TX_STOP = 2'b11;

    // Internal signals
    reg [15:0] clk_count;
    reg uart_clk;
    reg [1:0] rx_state, tx_state;
    reg [3:0] read_count, write_count;
    reg [2:0] read_phase, write_tick;
    reg [7:0] read_buffer, write_buffer;
    reg read_parity, write_parity;

    // Clock generation
    always @(posedge SCLK or posedge RESET) begin
        if (RESET) begin
            clk_count <= 0;
            uart_clk <= 0;
        end else if (clk_count == UART_CLK_DIVIDER) begin
            clk_count <= 0;
            uart_clk <= ~uart_clk;
        end else begin
            clk_count <= clk_count + 1;
        end
    end

    // Receiver logic
    always @(posedge uart_clk or posedge RESET) begin
        if (RESET) begin
            rx_state <= RX_IDLE;
            read_count <= 0;
            read_phase <= 0;
            read_buffer <= 0;
            read_parity <= PARITY_ODD;
            RX_VALID <= 0;
            RX_PARITY <= 0;
            RX_DATA_OUT <= 0;
        end else begin
            case (rx_state)
                RX_IDLE: begin
                    if (!RX) begin
                        rx_state <= RX_START;
                        read_phase <= 0;
                    end
                    RX_VALID <= 0;
                end
                RX_START: begin
                    if (read_phase == 7) begin
                        rx_state <= RX_DATA;
                        read_count <= 0;
                        read_phase <= 0;
                        read_parity <= PARITY_ODD;
                    end else begin
                        read_phase <= read_phase + 1;
                    end
                end
                RX_DATA: begin
                    if (read_phase == 7) begin
                        read_buffer[read_count] <= RX;
                        read_parity <= read_parity ^ RX;
                        if (read_count == 7) begin
                            rx_state <= PARITY_ENABLED ? RX_STOP : RX_IDLE;
                            RX_DATA_OUT <= {RX, read_buffer[6:0]};
                        end else begin
                            read_count <= read_count + 1;
                        end
                        read_phase <= 0;
                    end else begin
                        read_phase <= read_phase + 1;
                    end
                end
                RX_STOP: begin
                    if (read_phase == 7) begin
                        rx_state <= RX_IDLE;
                        RX_VALID <= 1;
                        RX_PARITY <= read_parity;
                    end else begin
                        read_phase <= read_phase + 1;
                    end
                end
            endcase
        end
    end

    // Transmitter logic
    always @(posedge uart_clk or posedge RESET) begin
        if (RESET) begin
            tx_state <= TX_IDLE;
            write_count <= 0;
            write_tick <= 0;
            write_buffer <= 0;
            write_parity <= PARITY_ODD;
            TX <= 1;
            TX_READY <= 1;
        end else begin
            case (tx_state)
                TX_IDLE: begin
                    if (TX_VALID) begin
                        tx_state <= TX_START;
                        write_buffer <= TX_DATA_IN;
                        write_parity <= PARITY_ODD;
                        TX_READY <= 0;
                    end
                end
                TX_START: begin
                    if (write_tick == 7) begin
                        TX <= 0;
                        tx_state <= TX_DATA;
                        write_count <= 0;
                        write_tick <= 0;
                    end else begin
                        write_tick <= write_tick + 1;
                    end
                end
                TX_DATA: begin
                    if (write_tick == 7) begin
                        TX <= write_buffer[write_count];
                        write_parity <= write_parity ^ write_buffer[write_count];
                        if (write_count == 7) begin
                            tx_state <= PARITY_ENABLED ? TX_STOP : TX_IDLE;
                            TX_READY <= 1;
                        end else begin
                            write_count <= write_count + 1;
                        end
                        write_tick <= 0;
                    end else begin
                        write_tick <= write_tick + 1;
                    end
                end
                TX_STOP: begin
                    if (write_tick == 7) begin
                        TX <= PARITY_ENABLED ? write_parity : 1;
                        tx_state <= TX_IDLE;
                        write_tick <= 0;
                    end else begin
                        write_tick <= write_tick + 1;
                    end
                end
            endcase
        end
    end

endmodule

files.conformal_rtl_origen_006348.do:
// Conformal LEC RTL vs RTL: combinational equivalence (no netlist, no technology library).
// Golden and revised in ./rtl/golden.v, ./rtl/revised.v.
// Uses -SystemVerilog for SV support (logic, always_comb, int, $bits, etc); backward compatible with Verilog.
// NOTE: Conformal uses // for comments. Do NOT use # (Conformal treats # as a command and aborts).

set undefined cell black_box
read design ./rtl/golden.v -SystemVerilog -Golden
read design ./rtl/revised.v -SystemVerilog -Revised

// Switch to LEC mode and compare
set system mode lec
add compared points -all
compare
exit -force

