parameter M = 18;  
parameter N = 18;  
parameter K = 1;

parameter ITER = (N/K) + ((N%K) ? 1:0);
parameter K2 = (N%K) ? (N%K):K;

parameter INI   = 2'b00,
		  LOAD  = 2'b01,
		  CALC  = 2'b10,
		  READY = 2'b11; 

input clock, reset;
input start;
input [M-1:0] A;
input [N-1:0] B;
output ready;
output [M+N-1:0] R;

reg [M+K-1:0] reg_H;
reg [M-1:0] reg_A;
reg [N-1:0] reg_B;

reg [M-1:0] reg_Ai;
reg [N-1:0] reg_Bi;

reg [1:0] STATE;
reg [1:0] NEXTSTATE;

reg loadA, loadB, loadH;
reg shH, shB;
reg resetQ;

wire [M+K-1:0] fa_sum;
reg [M+K-1:0] mult_A_B;

reg [7:0] Q;
wire [7:0] D;
reg EN;

assign D = Q + 8'b00000001;
assign ready = (STATE == INI || STATE == READY);
assign fa_sum = mult_A_B[M+K-1:0] + { {K{ reg_H[M-1] }}, reg_H[M-1:0]};
assign R = {reg_H[M-1:0], reg_B[N-1:0]};

