	if(reset)
		reg_A <= {M{1'b0}};
	else if(loadA)
		reg_A <= reg_Ai;
end

always @(posedge clock) begin
	if(reset)
		reg_Ai <= {M{1'b0}};
	else if(start & ~loadA)
		reg_Ai <= A;
end

always @(posedge clock) begin
	if(reset)
		reg_Bi <= {M{1'b0}};
	else if(start & ~loadB)
		reg_Bi <= B;
end

always @(posedge clock) begin
	if(reset || loadH)
		reg_H <= {(M+K-1){1'b0}};
	else if(shH) begin
		if((N%K) && Q == ITER)
			reg_H <= { {K2{ fa_sum[M+K-1] }}, fa_sum[M+K-1:K2]};
		else
			reg_H <= { {K{ fa_sum[M+K-1] }}, fa_sum[M+K-1:K]};
