				                           -( ( { {K{reg_A[M-1]}}, reg_A } & {(M+K){reg_B[1]}} ) << 1 ) );

				3'b011: mult_A_B =    ( { {K{reg_A[M-1]}}, reg_A } & {(M+K){reg_B[0]}} ) +
				                    ( ( { {K{reg_A[M-1]}}, reg_A } & {(M+K){reg_B[1]}} ) << 1 ) +
				                    ( (Q != ITER) ? 
