		end

		LOAD: begin
			NEXTSTATE = CALC;
		end

		CALC: begin
			if(Q == ITER)
				NEXTSTATE = INI;
			else
				NEXTSTATE = CALC;
		end

		READY: begin
			if(start == 0)
				NEXTSTATE = INI;
			else
				NEXTSTATE = READY;
		end

	endcase
end

always @* begin
	EN = 0;
	loadA = 0;
	loadB = 0;
	loadH = 0;
	shH = 0;
	shB = 0;
	resetQ = 0;

	case(STATE)

		LOAD: begin
			loadA = 1;
			loadB = 1;
			loadH = 1;
			resetQ = 1;
		end

