module autovcoder_072758 (
    clk,
    rst,
    press,
    scan_code,
    buf_flag,
    key_buf_code,
    key_buf_code_2,
    key_buf_code_3,
    key_buf_code_4
);
  input clk, rst, press;
  input [3:0] scan_code;
  output [5:0] buf_flag;
  output [23:0] key_buf_code;
  output [23:0] key_buf_code_2;
  output [31:0] key_buf_code_3;
  output [31:0] key_buf_code_4;

  reg [ 5:0] buf_flag;
  reg [23:0] key_buf_code;
  reg [23:0] key_buf_code_2;
  reg [31:0] key_buf_code_3;
  reg [31:0] key_buf_code_4;

  always @(posedge clk or posedge rst) begin
    if (rst) begin
      buf_flag = 6'b000000;
      key_buf_code = 24'h000000;
      key_buf_code_2 = 24'h000000;
      key_buf_code_3 = 32'h00000000;
      key_buf_code_4 = 32'h00000000;
    end else if (press == 1'b1) begin
      buf_flag = {buf_flag[4:0], 1'b1};
      key_buf_code[23:0] = {key_buf_code[19:0], scan_code};
      key_buf_code_3[31:0] = {key_buf_code_3[27:0], scan_code};
      key_buf_code_4[31:0] = {key_buf_code_4[27:0], scan_code};
      if(scan_code == 4'b0001 || scan_code == 4'b0011 || scan_code == 4'b0101 || scan_code == 4'b0111 || scan_code == 4'b1001)begin
        key_buf_code_2[23:0] = {key_buf_code_2[19:0], scan_code};
      end
      if (scan_code == 4'b1111) begin
        key_buf_code_4 = 32'h00000000;
      end


    end

  end
endmodule

files.autovcoder_127591.v:
module autovcoder_127591 (
    input wire clk,
    input wire reset,
    input wire send,
    input wire receive,
    input wire [7:0] data_in,
    output reg [7:0] data_out,
    output reg busy,
    output reg sclk,
    output reg mosi,
    input wire miso
);
    reg [2:0] bit_count;
    reg [7:0] shift_register;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            busy <= 0;
            bit_count <= 0;
            shift_register <= 0;
            sclk <= 0;
            mosi <= 0;
            data_out <= 0;
        end else if (send && !busy) begin
            busy <= 1;
            shift_register <= data_in;
            bit_count <= 0;
            sclk <= 0;
        end else if (busy) begin
            sclk <= ~sclk; // Toggle sclk
            if (sclk) begin
                mosi <= shift_register[7]; // Send MSB first
                shift_register <= {shift_register[6:0], 1'b0}; // Shift left
                bit_count <= bit_count + 1;
            end else begin
                if (bit_count < 8) begin
                    data_out <= {data_out[6:0], miso}; // Receive data
                end
                if (bit_count == 7) begin
                    busy <= 0; // Done sending and receiving
                end
            end
        end
    end
endmodule

files.autovcoder_141427.v:
module autovcoder_141427 (  
    input clk,  
    input start,  
    input [7:0] data_in,  
    output reg sda,  
    output reg scl,  
    output reg ready  
);  
    reg [3:0] state;  
    reg [7:0] data;  

    localparam IDLE = 4'd0,  
               START = 4'd1,  
               SEND = 4'd2,  
               STOP = 4'd3;  

    always @(posedge clk) begin  
        case (state)  
            IDLE: begin  
                ready <= 1;  
                if (start) begin  
                    state <= START;  
                    data <= data_in;  
                    sda <= 1;  
                    scl <= 0;  
                end  
            end  
            START: begin  
                sda <= 0;  
                state <= SEND;  
            end  
            SEND: begin  
                sda <= data[7];  
                data <= {data[6:0], 1'b0};  
                if (data == 8'b0) begin  
                    state <= STOP;  
                end  
            end  
            STOP: begin  
                sda <= 1;  
                ready <= 1;  
                state <= IDLE;  
            end  
        endcase  
    end  
endmodule

