              S4 = 3'b100, S5 = 3'b101, S6 = 3'b110, S7 = 3'b111;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            state <= S0;
            valid <= 0;
            output_symbol <= 2'b00;
        end else begin
            state <= next_state;
            valid <= 1; // Assume valid output after state transition
        end
    end

    always @(*) begin
        case (state)
