    ** Here the internal registers are defined                               **
    ***************************************************************************/
  reg [NrOfBits-1:0] s_state_reg;
  reg [NrOfBits-1:0] s_state_reg_neg_edge;

  assign Q = cs ? {NrOfBits{1'bz}} : ((ActiveLevel) ? s_state_reg : s_state_reg_neg_edge);

