                    count <= count + 1'b1;
                end else if (count == 9'd256) begin
                    wren <= 1'b0;
                    count <= count + 1'b1;
                end else begin // count == 9'd257
                    rdy <= 1'b1;
                    go <= 1'b0;
                    addr <= 8'bx;
                    wrdata <= 8'bx;
                    count <= 9'd0;
                end
            end
        end
    end

