module origen_157439(
    input clk,
    input keyBounce,
    output keyDeBounce
);

reg [7:0] counter = `MIN;
reg lockDeBounce = 1'b1;

assign keyDeBounce = lockDeBounce ? 1'b1 : keyBounce;

`ifdef DEBUG_DEBOUNCE
assign dclk = clk;
assign dkeyBounce = keyBounce;
`endif

always @(posedge clk) begin
    if (counter == `MIN) begin
        lockDeBounce <= 1'b1;
        if (~keyBounce)
            counter <= counter + `TIK;
    end else if (counter == `MAX) begin
        lockDeBounce <= 1'b0;
        if (keyBounce)
            counter <= counter - `TIK;
    end else begin
        if (lockDeBounce) begin
            if (~keyBounce)
                counter <= counter + `TIK;
            else
                counter <= `MIN;
        end else begin
            if (keyBounce)
                counter <= counter - `TIK;
            else
                counter <= `MAX;
        end
    end
end

