module autovcoder_130270 (
    input wire clk,
    input wire rst,
    input wire start,
    input wire rw, // 1 for write, 0 for read
    input wire [31:0] addr,
    input wire [31:0] data_in,
    output reg [31:0] data_out,
    output reg ready,
    output reg error
);
    reg [1:0] state; // 0: idle, 1: read, 2: write, 3: done
    parameter IDLE = 0, READ = 1, WRITE = 2, DONE = 3;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            ready <= 1;
            error <= 0;
        end else begin
            case (state)
                IDLE: begin
                    if (start) begin
                        if (rw) begin
                            state <= WRITE;
                            ready <= 0;
                        end else begin
                            state <= READ;
                            ready <= 0;
                        end
                    end
                end
                READ: begin
                    // Simulate reading from memory
                    data_out <= data_in; // Replace with actual memory read
                    state <= DONE;
                end
                WRITE: begin
                    // Simulate writing to memory
                    // Replace with actual memory write
                    state <= DONE;
                end
                DONE: begin
                    ready <= 1;
                    state <= IDLE;
                end
            endcase
        end
    end
endmodule

