module autovcoder_072826 (
    input  wire       clock,
    input  wire       reset,
    input  wire       chip_select_n,
    input  wire       read_enable_n,
    input  wire       write_enable_n,
    input  wire [1:0] address,
    input  wire [7:0] data_bus_in,
    output reg  [7:0] internal_data_bus,
    output wire       write_port_a,
    output wire       write_port_b,
    output wire       write_port_c,
    output wire       write_control,
    output reg        read_port_a,
    output reg        read_port_b,
    output reg        read_port_c
);

  reg prev_write_enable_n;
  wire write_flag;
  reg [2:0] stable_address;
  always @(posedge clock or posedge reset)
    if (reset) internal_data_bus <= 8'b00000000;
    else if (~write_enable_n & ~chip_select_n) internal_data_bus <= data_bus_in;
    else internal_data_bus <= internal_data_bus;
  always @(posedge clock or posedge reset)
    if (reset) prev_write_enable_n <= 1'b1;
    else if (chip_select_n) prev_write_enable_n <= 1'b1;
    else prev_write_enable_n <= write_enable_n;
  assign write_flag = ~prev_write_enable_n & write_enable_n;
  always @(posedge clock or posedge reset)
    if (reset) stable_address <= 2'b00;
    else stable_address <= address;
  assign write_port_a  = (stable_address == 2'b00) & write_flag;
  assign write_port_b  = (stable_address == 2'b01) & write_flag;
  assign write_port_c  = (stable_address == 2'b10) & write_flag;
  assign write_control = (stable_address == 2'b11) & write_flag;
  always @(*) begin
    read_port_a = 1'b0;
    read_port_b = 1'b0;
    read_port_c = 1'b0;
    if (~read_enable_n & ~chip_select_n)
      case (address)
        2'b00:   read_port_a = 1'b1;
        2'b01:   read_port_b = 1'b1;
        2'b10:   read_port_c = 1'b1;
        default: read_port_a = 1'b1;
      endcase
  end
endmodule

files.autovcoder_063335.v:
module autovcoder_063335 (
    input         clk,
    input         reset,
    input  [ 5:0] frame,
    input  [ 7:0] subframe,
    input  [ 5:0] x,
    input  [ 5:0] y,
    output [23:0] rgb24
);

  wire blank;
  wire [2:0] row, col;
  wire [7:0] x_lo, y_lo;

  assign blank = !x[2:0] || !y[2:0];
  assign row   = y[5:3];
  assign col   = x[5:3];

  // Trickery: the minimum value that doesn't get gamma-corrected
  // to zero is 21.  So we'll put ceil(21/2) in the low four bits
  // of x_lo and y_lo instead of repeating the high bits.
  // It's wrong, but it's less visually objectionable than having
  // pixels flicker between nonzero and zero.
  //
  // assign x_lo    = {x[2:0], x[2:0], x[2:1]};
  // assign y_lo    = {y[2:0], y[2:0], y[2:1]};
  assign x_lo  = {x[2:0], 4'd11};
  assign y_lo  = {y[2:0], 4'd11};

  reg [7:0] red, green, blue;
  reg in_gamma;
  always @(posedge clk) begin
    in_gamma <= ((x - frame[5:0]) & 6'h20) ? 1 : 0;
    if (blank) begin
      red   <= 0;
      green <= 0;
      blue  <= 0;
    end else begin
      red   <= (row[0] ? y_lo : 0) + (col[0] ? x_lo : 0);
      green <= (row[1] ? y_lo : 0) + (col[1] ? x_lo : 0);
      blue  <= (row[2] ? y_lo : 0) + (col[2] ? x_lo : 0);
    end
  end

  reg [15:0] gamma_table[0:255];
  initial $readmemh("gamma_table.hex", gamma_table);

  reg [7:0] red_g, green_g, blue_g;
  always @(posedge clk) begin
    red_g   <= in_gamma ? gamma_table[red][15:8] : red;
    green_g <= in_gamma ? gamma_table[green][15:8] : green;
    blue_g  <= in_gamma ? gamma_table[blue][15:8] : blue;
  end

  assign rgb24 = {blue_g, green_g, red_g};

endmodule

files.origen_218900.v:
module origen_218900(
    input E,
    input W,
    input clk,
    input reset,
    output reg out
);

reg [1:0] State;
reg z;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        State <= 2'b00;
        z <= 1'b0;
    end
    else begin
        case (State)
            2'b00: // S0
                begin
                    z <= 1'b1;
                    if (~E & W)
                        State <= 2'b01;
                    else if (E & W)
                        State <= 2'b10;
                    else if (E & ~W)
                        State <= 2'b11;
                end
            2'b01: // S1
                begin
                    z <= 1'b0;
                    if (E)
                        State <= 2'b10;
                end
            2'b10: // S2
                begin
                    z <= 1'b0;
                    if (~E & ~W)
                        State <= 2'b00;
                end
            2'b11: // S3
                begin
                    z <= 1'b0;
                    if (~W)
                        State <= 2'b10;
                end
        endcase
    end
end

assign out = z;

endmodule

