module autovcoder_010351 #(
    parameter DATA_WIDTH      = 8,
    parameter DEPTH           = 64,
    parameter NUM_WORDS       = 4,
    parameter RAM_STYLE       = "auto",
    parameter OUTPUT_REGISTER = "false"
) (
    output [DATA_WIDTH*NUM_WORDS-1:0] rd_data,
    input  [          DATA_WIDTH-1:0] wr_data,
    input  [       $clog2(DEPTH)-1:0] rd_addr,
    input  [       $clog2(DEPTH)-1:0] wr_addr,
    input  [           NUM_WORDS-1:0] wr_en,
    input                             rd_en,
    input                             clk
);

  (* ram_style = RAM_STYLE *) reg [DATA_WIDTH*NUM_WORDS-1:0] ram[0:DEPTH-1];

  // Write port
  genvar i;

  generate
    for (i = 0; i < NUM_WORDS; i = i + 1) begin : gen0
      always @(posedge clk) begin
        if (wr_en[i]) begin
          ram[wr_addr][(i+1)*DATA_WIDTH-1:i*DATA_WIDTH] <= wr_data;
        end
      end
    end
  endgenerate

  // Read port
  reg [DATA_WIDTH*NUM_WORDS-1:0] rd_data_reg;

  always @(posedge clk) begin
    if (rd_en) begin
      rd_data_reg <= ram[rd_addr];
    end else begin
      rd_data_reg <= rd_data_reg;
    end
  end

  // Output
  generate
    if (OUTPUT_REGISTER == "true") begin : gen1
      reg [DATA_WIDTH*NUM_WORDS-1:0] rd_data_reg_2;

      always @(posedge clk) begin
        rd_data_reg_2 <= rd_data_reg;
      end

      assign rd_data = rd_data_reg_2;
    end else if (OUTPUT_REGISTER == "false") begin : gen2
      assign rd_data = rd_data_reg;
    end
  endgenerate

endmodule

files.autovcoder_132817.v:
module autovcoder_132817 (
    input clk,
    input rst,
    input [31:0] plaintext,
    input [31:0] e,
    input [31:0] n,
    output reg [31:0] ciphertext
);
    reg [31:0] result;
    reg [31:0] base;
    reg [31:0] exp;
    reg [31:0] mod;
    reg [4:0] state;

    parameter IDLE = 0, CALC = 1, DONE = 2;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            result <= 1;
            base <= plaintext;
            exp <= e;
            mod <= n;
            ciphertext <= 0;
        end else begin
            case (state)
                IDLE: begin
                    if (exp > 0) begin
                        state <= CALC;
                    end else begin
                        ciphertext <= 0;
                        state <= DONE;
                    end
                end
                CALC: begin
                    if (exp[0] == 1) begin
                        result <= (result * base) % mod;
                    end
                    base <= (base * base) % mod;
                    exp <= exp >> 1;

                    if (exp == 0) begin
                        state <= DONE;
                    end
                end
                DONE: begin
                    ciphertext <= result;
                    state <= IDLE; // Reset to idle for next operation
                end
            endcase
        end
    end
endmodule

files.origen_031131.v:
module origen_031131 #(
    parameter WIDTH = 8,
    parameter DEPTH = 4,
    parameter OFLOW = "REPLACE"
) (
    input wire reset,
    input wire clk,
    input wire [WIDTH-1:0] wdata,
    input wire store,
    input wire read,
    output reg [WIDTH-1:0] rdata,
    output wire empty,
    output wire full,
    output reg overflow
);

    localparam NELEM = 2**DEPTH;

    reg [WIDTH-1:0] buffer [0:NELEM-1];
    reg [DEPTH-1:0] rpos, wpos;
    wire [DEPTH-1:0] wpos_next;
    wire dostore;

    assign empty = (rpos == wpos);
    assign full = (wpos_next == rpos);
    assign wpos_next = wpos + 1'b1;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            rpos <= {DEPTH{1'b0}};
            wpos <= {DEPTH{1'b0}};
            overflow <= 1'b0;
        end else begin
            if (read && !empty) begin
                rdata <= buffer[rpos];
                rpos <= rpos + 1'b1;
            end
            if (dostore) begin
                buffer[wpos] <= wdata;
                wpos <= wpos_next;
            end
            overflow <= (store && full);
        end
    end

    generate
        if (OFLOW == "REPLACE") begin : gen_replace
            assign dostore = store;
        end else if (OFLOW == "IGNORE") begin : gen_ignore
            assign dostore = store && !full;
        end else begin : gen_error
            OFLOW_value_not_valid error_here();
        end
    endgenerate

endmodule

files.origen_114079.v:
module origen_114079 (
    input  wire        clk_i,
    input  wire        rstn_i,
    input  wire        test_mode_i,
    input  wire        cfg_clk_en_i,
    input  wire [15:0] cfg_div_i,
    output wire        sck_o,
    output wire        cfg_clk_en_o
);

    reg [15:0] r_counter;
    reg [15:0] r_sampled_config;
    reg        r_clk;
    reg        r_clk_en;

    always @(posedge clk_i or negedge rstn_i) begin
        if (!rstn_i) begin
            r_counter <= 16'b0;
            r_sampled_config <= 16'b0;
            r_clk <= 1'b0;
            r_clk_en <= 1'b0;
        end else begin
            r_clk_en <= cfg_clk_en_i;

            if (cfg_clk_en_i) begin
                if (r_counter == r_sampled_config) begin
                    r_counter <= 16'b0;
                    r_clk <= ~r_clk;
                    r_sampled_config <= cfg_div_i;
                end else begin
                    r_counter <= r_counter + 1'b1;
                end
            end else begin
                r_counter <= 16'b0;
                r_clk <= 1'b0;
                r_sampled_config <= cfg_div_i;
            end
        end
    end

    assign cfg_clk_en_o = r_clk_en;

    `ifdef PULP_DFT
        wire sck_mux;
        pulp_clock_mux2 clk_mux_i (
            .clk0_i(r_clk),
            .clk1_i(clk_i),
            .clk_sel_i(test_mode_i),
            .clk_o(sck_mux)
        );
        assign sck_o = sck_mux;
    `else
        assign sck_o = r_clk;
    `endif

endmodule

files.origen_126300.v:
module origen_126300 (
    input wire clk,
    input wire rst,
    input wire [3:0] A,
    input wire [3:0] B,
    output reg [7:0] result
);

    // Pipeline registers
    reg [3:0] multiplicand_reg;
    reg [2:0] multiplier_reg;
    reg [7:0] partial_product;
    reg [2:0] counter;

    // Intermediate signals
    wire [4:0] extended_multiplicand;
    wire [4:0] neg_extended_multiplicand;

    // Sign extension
    assign extended_multiplicand = {A[3], A};
    assign neg_extended_multiplicand = -extended_multiplicand;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            multiplicand_reg <= 4'b0;
            multiplier_reg <= 3'b0;
            partial_product <= 8'b0;
            counter <= 3'b0;
            result <= 8'b0;
        end else begin
            // Stage 1: Load inputs
            multiplicand_reg <= A;
            multiplier_reg <= B[2:0];

            // Stage 2: Booth's algorithm
            case ({multiplier_reg[1:0], 1'b0})
                3'b000, 3'b111: partial_product <= partial_product;
                3'b001, 3'b010: partial_product <= partial_product + {extended_multiplicand, 3'b0};
                3'b101, 3'b110: partial_product <= partial_product + {neg_extended_multiplicand, 3'b0};
                3'b011: partial_product <= partial_product + {extended_multiplicand, 3'b0} + {extended_multiplicand, 2'b0};
                3'b100: partial_product <= partial_product + {neg_extended_multiplicand, 3'b0} + {neg_extended_multiplicand, 2'b0};
            endcase

            // Stage 3: Shift and count
            multiplier_reg <= {1'b0, multiplier_reg[2:1]};
            partial_product <= {partial_product[7], partial_product[7:1]};
            counter <= counter + 1;

            // Stage 4: Output result
            if (counter == 3'b011) begin
                result <= partial_product;
                counter <= 3'b0;
                partial_product <= 8'b0;
            end
        end
    end

endmodule

files.origen_161526.v:
module origen_161526(
    input clk,
    input rst,
    input period_flag,
    input signI,
    input [2:0] vc_level,
    input [7:0] vc1,
    input [7:0] vc2,
    output reg [3:0] Fo
);

reg [3:0] Fo_1;

initial begin
    Fo_1 = 4'b1010;
end

always @(posedge clk) begin
    if (rst) begin
        Fo <= Fo_1;
    end else if (period_flag) begin
        Fo_1 <= Fo;
        case (vc_level)
            3'b000: Fo <= 4'b0101;
            3'b001: begin
                if (signI == 1'b0 && vc2 > vc1) begin
                    Fo <= 4'b0111;
                end else if (signI == 1'b0 && vc2 <= vc1) begin
                    Fo <= 4'b0001;
                end else if (signI == 1'b1 && vc2 > vc1) begin
                    Fo <= 4'b1101;
                end else if (signI == 1'b1 && vc2 <= vc1) begin
                    Fo <= 4'b0111;
                end
            end
            3'b010: Fo <= 4'b0000;
            3'b011: begin
                if (signI == 1'b0 && vc2 < vc1) begin
                    Fo <= 4'b1011;
                end else if (signI == 1'b0 && vc2 >= vc1) begin
                    Fo <= 4'b1110;
                end else if (signI == 1'b1 && vc2 < vc1) begin
