module origen_143077 (
    input wire [3:0] a,
    input wire [3:0] b,
    input wire clk,
    output reg [7:0] result,
    output reg done
);

    // State definitions
    localparam IDLE = 1'b0;
    localparam MULTIPLY = 1'b1;

    reg state, next_state;
    reg [7:0] partial_products [3:0];
    reg [7:0] sum;
    reg [1:0] counter;

    // State machine
    always @(posedge clk) begin
        state <= next_state;
    end

    always @(*) begin
        case (state)
            IDLE: next_state = done ? MULTIPLY : IDLE;
            MULTIPLY: next_state = (counter == 2'b11) ? IDLE : MULTIPLY;
            default: next_state = IDLE;
        endcase
    end

    // Pipeline stage 1: Compute partial products
    always @(posedge clk) begin
        if (state == MULTIPLY) begin
            partial_products[0] <= a[0] ? {4'b0000, b} : 8'b0;
            partial_products[1] <= a[1] ? {3'b000, b, 1'b0} : 8'b0;
            partial_products[2] <= a[2] ? {2'b00, b, 2'b00} : 8'b0;
            partial_products[3] <= a[3] ? {1'b0, b, 3'b000} : 8'b0;
        end
    end

    // Pipeline stage 2: Compute final result
    always @(posedge clk) begin
        if (state == MULTIPLY) begin
            sum <= partial_products[0] + partial_products[1] + partial_products[2] + partial_products[3];
            if (counter == 2'b11) begin
                result <= sum;
                done <= 1'b1;
            end else begin
                counter <= counter + 1'b1;
            end
        end else begin
            counter <= 2'b00;
            done <= 1'b0;
        end
    end

endmodule

