module shift_register #(
    parameter WIDTH = 8
) (
    input wire clk,
    input wire rst_n,
    input wire shift_in,
    output wire shift_out
);

    reg [WIDTH-1:0] shift_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            shift_reg <= {WIDTH{1'b0}};
        end else begin
            shift_reg <= {shift_reg[WIDTH-2:0], shift_in};
        end
    end

    assign shift_out = shift_reg[WIDTH-1];

endmodule

