    always @(*) begin
        case(d)
            8'h75: begin dir = 0; xy = 1; end // Move up
            8'h6B: begin dir = 0; xy = 0; end // Move left
            8'h72: begin dir = 1; xy = 0; end // Move right
            8'h74: begin dir = 1; xy = 1; end // Move down
