            x <= 5'b0;
            y <= 5'b0;
        end else begin
            if (xy) begin
                if (dir) y <= (y == 5'b11111) ? y : y + 1;
                else y <= (y == 5'b00000) ? y : y - 1;
            end else begin
                if (dir) x <= (x == 5'b11111) ? x : x + 1;
