module rtlpp_05323(
    input           clk, reset,
    input   [15:0]  IR,
    input           N, Z, C,
    output  [2:0]   W_Adr, R_Adr, S_Adr,
    output          adr_sel, s_sel,
    output          pc_ld, pc_inc, pc_sel, ir_ld,
    output          mw_en, rw_en,
    output  [3:0]   alu_op,
    output  [7:0]   status
);

reg     [2:0]   W_Adr, R_Adr, S_Adr;
reg             adr_sel, s_sel;
reg             pc_ld, pc_inc, pc_sel, ir_ld;
reg             mw_en, rw_en;
reg     [3:0]   alu_op;
reg     [4:0]   state;
reg     [4:0]   nextstate;
reg     [7:0]   status;
reg             ps_N, ps_Z, ps_C;
reg             ns_N, ns_Z, ns_C;

parameter   RESET = 0, FETCH = 1, DECODE = 2, 
            ADD = 3, SUB = 4, CMP = 5, MOV = 6, 
            INC = 7, DEC = 8, SHL = 9, SHR = 10, 
            LD = 11, STO = 12, LDI = 13, 
            JE = 14, JNE = 15, JC = 16, JMP = 17, 
            HALT = 18, 
            ILLEGAL_OP = 31;

always @ (posedge clk or posedge reset) begin
    if (reset) 
        state <= RESET;
    else
        state <= nextstate;
end

always @ (posedge clk or posedge reset) begin
    if (reset) 
        {ps_N, ps_Z, ps_C} <= 3'b0;
    else 
        {ps_N, ps_Z, ps_C} <= {ns_N, ns_Z, ns_C};
end

always @(*) begin
    case (state)
        RESET: begin 
            W_Adr = 3'b000; R_Adr = 3'b000; S_Adr = 3'b000;
            adr_sel = 1'b0; s_sel = 1'b0;
            pc_ld = 1'b0; pc_inc = 1'b0; pc_sel = 1'b0; ir_ld = 1'b0;
            mw_en = 1'b0; rw_en = 1'b0; alu_op = 4'b0000;
            {ns_N, ns_Z, ns_C} = 3'b0;
            status = 8'hFF;
            nextstate = FETCH;
        end
        FETCH: begin 
            W_Adr = 3'b000; R_Adr = 3'b000; S_Adr = 3'b000;
            adr_sel = 1'b0; s_sel = 1'b0;
            pc_ld = 1'b0; pc_inc = 1'b1; pc_sel = 1'b0; ir_ld = 1'b1;
            mw_en = 1'b0; rw_en = 1'b0; alu_op = 4'b0000;
            {ns_N, ns_Z, ns_C} = {ps_N, ps_Z, ps_C};
            status = 8'h80;
            nextstate = DECODE;
        end
        DECODE: begin 
            W_Adr = 3'b000; R_Adr = 3'b000; S_Adr = 3'b000;
            adr_sel = 1'b0; s_sel = 1'b0;
            pc_ld = 1'b0; pc_inc = 1'b0; pc_sel = 1'b0; ir_ld = 1'b0;
            mw_en = 1'b0; rw_en = 1'b0; alu_op = 4'b0000;
            {ns_N, ns_Z, ns_C} = {ps_N, ps_Z, ps_C};
            status = 8'hC0;
            case (IR[15:9])
                7'h70: nextstate = ADD;
                7'h71: nextstate = SUB;
                7'h72: nextstate = CMP;
                7'h73: nextstate = MOV;
                7'h74: nextstate = SHL;
                7'h75: nextstate = SHR;
                7'h76: nextstate = INC;
                7'h77: nextstate = DEC;
                7'h78: nextstate = LD;
                7'h79: nextstate = STO;
                7'h7A: nextstate = LDI;
                7'h7B: nextstate = HALT;
                7'h7C: nextstate = JE;
                7'h7D: nextstate = JNE;
                7'h7E: nextstate = JC;
                7'h7F: nextstate = JMP;
                default: nextstate = ILLEGAL_OP;
            endcase
        end
        ADD: begin
            W_Adr = IR[8:6]; R_Adr = IR[5:3]; S_Adr = IR[2:0];
            adr_sel = 1'b0; s_sel = 1'b0;
            pc_ld = 1'b0; pc_inc = 1'b0; pc_sel = 1'b0; ir_ld = 1'b0;
            mw_en = 1'b0; rw_en = 1'b1; alu_op = 4'b0100;
            {ns_N, ns_Z, ns_C} = {N, Z, C};
            status = {ps_N, ps_Z, ps_C, 5'b00000};
            nextstate = FETCH;
        end
        SUB: begin
            W_Adr = IR[8:6]; R_Adr = IR[5:3]; S_Adr = IR[2:0];
            adr_sel = 1'b0; s_sel = 1'b0;
            pc_ld = 1'b0; pc_inc = 1'b0; pc_sel = 1'b0; ir_ld = 1'b0;
            mw_en = 1'b0; rw_en = 1'b1; alu_op = 4'b0101;
            {ns_N, ns_Z, ns_C} = {N, Z, C};
            status = {ps_N, ps_Z, ps_C, 5'b00001};
            nextstate = FETCH;
        end
        CMP: begin
            W_Adr = 3'b000; R_Adr = IR[5:3]; S_Adr = IR[2:0];
            adr_sel = 1'b0; s_sel = 1'b0;
            pc_ld = 1'b0; pc_inc = 1'b0; pc_sel = 1'b0; ir_ld = 1'b0;
            mw_en = 1'b0; rw_en = 1'b0; alu_op = 4'b0101;
            {ns_N, ns_Z, ns_C} = {N, Z, C};
            status = {ps_N, ps_Z, ps_C, 5'b00010};
            nextstate = FETCH;
        end
        MOV: begin
            W_Adr = IR[8:6]; R_Adr = 3'b000; S_Adr = IR[2:0];
