            mw_en = 1'b0; rw_en = 1'b1; alu_op = 4'b0000;
            {ns_N, ns_Z, ns_C} = {ps_N, ps_Z, ps_C};
            status = {ps_N, ps_Z, ps_C, 5'b00011};
            nextstate = FETCH;
        end
        SHL: begin
            W_Adr = IR[8:6]; R_Adr = 3'b000; S_Adr = IR[2:0];
