            nextstate = FETCH;
        end
        INC: begin
            W_Adr = IR[8:6]; R_Adr = 3'b000; S_Adr = IR[2:0];
            adr_sel = 1'b0; s_sel = 1'b0;
            pc_ld = 1'b0; pc_inc = 1'b0; pc_sel = 1'b0; ir_ld = 1'b0;
            mw_en = 1'b0; rw_en = 1'b1; alu_op = 4'b0010;
            {ns_N, ns_Z, ns_C} = {N, Z, C};
