module origen_129677 (
    input wire [511:0] data_in,
    input wire reset,
    input wire clk,
    output reg [255:0] hash_value,
    output reg valid
);

// Constants
parameter [255:0] H0 = 256'h6a09e667bb67ae853c6ef372a54ff53a510e527f9b05688c1f83d9ab5be0cd19;
parameter [31:0] K [0:63] = {
    32'h428a2f98, 32'h71374491, 32'hb5c0fbcf, 32'he9b5dba5,
    32'h3956c25b, 32'h59f111f1, 32'h923f82a4, 32'hab1c5ed5,
    32'hd807aa98, 32'h12835b01, 32'h243185be, 32'h550c7dc3,
    32'h72be5d74, 32'h80deb1fe, 32'h9bdc06a7, 32'hc19bf174,
    32'he49b69c1, 32'hefbe4786, 32'h0fc19dc6, 32'h240ca1cc,
    32'h2de92c6f, 32'h4a7484aa, 32'h5cb0a9dc, 32'h76f988da,
    32'h983e5152, 32'ha831c66d, 32'hb00327c8, 32'hbf597fc7,
    32'hc6e00bf3, 32'hd5a79147, 32'h06ca6351, 32'h14292967,
    32'h27b70a85, 32'h2e1b2138, 32'h4d2c6dfc, 32'h53380d13,
    32'h650a7354, 32'h766a0abb, 32'h81c2c92e, 32'h92722c85,
    32'ha2bfe8a1, 32'ha81a664b, 32'hc24b8b70, 32'hc76c51a3,
    32'hd192e819, 32'hd6990624, 32'hf40e3585, 32'h106aa070,
    32'h19a4c116, 32'h1e376c08, 32'h2748774c, 32'h34b0bcb5,
    32'h391c0cb3, 32'h4ed8aa4a, 32'h5b9cca4f, 32'h682e6ff3,
    32'h748f82ee, 32'h78a5636f, 32'h84c87814, 32'h8cc70208,
    32'h90befffa, 32'ha4506ceb, 32'hbef9a3f7, 32'hc67178f2
};

// Internal registers
reg [31:0] w [0:63];
reg [31:0] a, b, c, d, e, f, g, h;
reg [5:0] round;
reg [2:0] state;

// State machine states
localparam IDLE = 3'd0;
localparam INIT = 3'd1;
localparam PROCESS = 3'd2;
localparam FINALIZE = 3'd3;

// Functions
function [31:0] ch;
    input [31:0] x, y, z;
    ch = (x & y) ^ (~x & z);
endfunction

function [31:0] maj;
    input [31:0] x, y, z;
    maj = (x & y) ^ (x & z) ^ (y & z);
endfunction

function [31:0] ep0;
    input [31:0] x;
    ep0 = {x[1:0], x[31:2]} ^ {x[12:0], x[31:13]} ^ {x[21:0], x[31:22]};
endfunction

function [31:0] ep1;
    input [31:0] x;
    ep1 = {x[5:0], x[31:6]} ^ {x[10:0], x[31:11]} ^ {x[24:0], x[31:25]};
endfunction

function [31:0] sig0;
    input [31:0] x;
    sig0 = {x[6:0], x[31:7]} ^ {x[17:0], x[31:18]} ^ (x >> 3);
endfunction

function [31:0] sig1;
    input [31:0] x;
    sig1 = {x[16:0], x[31:17]} ^ {x[18:0], x[31:19]} ^ (x >> 10);
endfunction

integer i;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        state <= IDLE;
        valid <= 0;
    end else begin
        case (state)
            IDLE: begin
                state <= INIT;
                valid <= 0;
            end
            INIT: begin
                {a, b, c, d, e, f, g, h} <= H0;
                for (i = 0; i < 16; i = i + 1) begin
                    w[i] <= data_in[511-i*32 -: 32];
                end
                for (i = 16; i < 64; i = i + 1) begin
                    w[i] <= sig1(w[i-2]) + w[i-7] + sig0(w[i-15]) + w[i-16];
                end
                round <= 0;
                state <= PROCESS;
            end
            PROCESS: begin
                if (round < 64) begin
                    reg [31:0] t1, t2;
                    t1 = h + ep1(e) + ch(e, f, g) + K[round] + w[round];
                    t2 = ep0(a) + maj(a, b, c);
                    h <= g;
                    g <= f;
                    f <= e;
                    e <= d + t1;
                    d <= c;
                    c <= b;
                    b <= a;
                    a <= t1 + t2;
                    round <= round + 1;
                end else begin
                    state <= FINALIZE;
                end
            end
            FINALIZE: begin
                hash_value <= {a + H0[255:224], b + H0[223:192], c + H0[191:160], d + H0[159:128],
                               e + H0[127:96], f + H0[95:64], g + H0[63:32], h + H0[31:0]};
                valid <= 1;
                state <= IDLE;
            end
        endcase
    end
end

endmodule

