module autovcoder_024128 (

    input sys_clk,
    input sys_nrst,

    input init_done,

    input [15 : 0] dac_din_l0,
    input [15 : 0] dac_din_r0,
    input [15 : 0] dac_din_l1,
    input [15 : 0] dac_din_r1,
    input [15 : 0] dac_din_l2,
    input [15 : 0] dac_din_r2,
    input [15 : 0] dac_din_l3,
    input [15 : 0] dac_din_r3,

    // Output to CS4344
