      dac_din_l0_r <= 'd0;
      dac_din_r0_r <= 'd0;
      dac_din_l1_r <= 'd0;
      dac_din_r1_r <= 'd0;
      dac_din_l2_r <= 'd0;
      dac_din_r2_r <= 'd0;
      dac_din_l3_r <= 'd0;
      dac_din_r3_r <= 'd0;
    end else if (dac_divider == 'd61) begin
      dac_din_l0_r <= dac_din_l0;
      dac_din_r0_r <= dac_din_r0;
      dac_din_l1_r <= dac_din_l1;
      dac_din_r1_r <= dac_din_r1;
      dac_din_l2_r <= dac_din_l2;
      dac_din_r2_r <= dac_din_r2;
