    output reg authentic
);

    // Constants
    localparam BLOCK_SIZE = 64;
    localparam HASH_SIZE = 256;

    // States
    localparam IDLE = 3'd0;
    localparam PROCESS_KEY = 3'd1;
    localparam PROCESS_INNER = 3'd2;
    localparam PROCESS_OUTER = 3'd3;
    localparam FINALIZE = 3'd4;

    // Internal registers
    reg [2:0] state;
    reg [63:0] padded_key;
