    reg [511:0] hash_block;
    reg hash_next;
    reg hash_last;

    sha256 sha256_inst (
        .clk(clk),
        .reset(reset),
        .init(hash_init),
        .block(hash_block),
        .next(hash_next),
        .last(hash_last),
        .digest(hash_out),
        .digest_valid(hash_valid)
    );

    // HMAC generation and checking logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            state <= IDLE;
            hmac_valid <= 0;
            authentic <= 0;
        end else begin
            case (state)
                IDLE: begin
                    if (msg_valid) begin
                        state <= PROCESS_KEY;
                        padded_key <= (key[63:56] == 0) ? {key, 56'b0} : key;
                        block_count <= 0;
                    end
                end

                PROCESS_KEY: begin
                    state <= PROCESS_INNER;
                    hash_init <= 1;
                    hash_block <= {padded_key ^ {64{8'h36}}, 448'b0};
                    hash_next <= 1;
                    hash_last <= 0;
                end

                PROCESS_INNER: begin
                    if (msg_valid) begin
                        block <= {block[503:0], msg_byte};
                        if (block_count == BLOCK_SIZE - 1) begin
                            hash_block <= block;
                            hash_next <= 1;
                            hash_last <= msg_last;
                            block_count <= 0;
                        end else begin
                            block_count <= block_count + 1;
                        end
                    end

                    if (hash_valid) begin
                        inner_hash <= hash_out;
                        if (msg_last) begin
                            state <= PROCESS_OUTER;
                            hash_init <= 1;
                            hash_block <= {padded_key ^ {64{8'h5c}}, 448'b0};
                            hash_next <= 1;
                            hash_last <= 0;
                        end
                    end
                end

                PROCESS_OUTER: begin
                    if (hash_valid) begin
                        state <= FINALIZE;
                        hash_block <= {inner_hash, 256'b0};
                        hash_next <= 1;
                        hash_last <= 1;
                    end
                end

                FINALIZE: begin
                    if (hash_valid) begin
                        hmac <= hash_out;
                        hmac_valid <= 1;
                        authentic <= (hmac == hash_out);
                        state <= IDLE;
                    end
                end
            endcase
        end
    end

